// ─────────────────────────────────────────────────────────────────────────────

const SHLOKAS = [
  // ── BHAGAVAD GITA ──────────────────────────────────────────────────────────
  {id:1,category:"Purpose",sanskrit:"कर्मण्येवाधिकारस्ते मा फलेषु कदाचन।\nमा कर्मफलहेतुर्भूर्मा ते सङ्गोऽस्त्वकर्मणि॥",translation:"You have a right to perform your duties, but never to the fruits thereof.",meaning:"Act fully but release attachment to outcomes. This is the Vedic cure for anxiety and overthinking.",source:"Bhagavad Gita 2.47"},
  {id:2,category:"Impermanence",sanskrit:"नासतो विद्यते भावो नाभावो विद्यते सतः।",translation:"The unreal has no existence; the real never ceases to be.",meaning:"What is truly you — awareness — never perishes. Only the temporary causes suffering.",source:"Bhagavad Gita 2.16"},
  {id:3,category:"Action",sanskrit:"योगः कर्मसु कौशलम्।",translation:"Yoga is skill in action.",meaning:"True yoga is not a pose — it is doing anything with complete presence and craft.",source:"Bhagavad Gita 2.50"},
  {id:4,category:"Letting Go",sanskrit:"त्यागाच्छान्तिरनन्तरम्।",translation:"From renunciation comes immediate peace.",meaning:"Release your grip on outcomes and identities that no longer serve you. Peace follows instantly.",source:"Bhagavad Gita 12.12"},
  {id:5,category:"Self",sanskrit:"आत्मा नित्यः शाश्वतोऽयं पुराणो न हन्यते हन्यमाने शरीरे।",translation:"The soul is eternal, ancient, unborn — it is not slain when the body is slain.",meaning:"Beyond your roles, titles, and fears lies your unchanging essence. No situation can destroy who you truly are.",source:"Bhagavad Gita 2.20"},
  {id:6,category:"Equanimity",sanskrit:"सुखदुःखे समे कृत्वा लाभालाभौ जयाजयौ।",translation:"Treat pleasure and pain, gain and loss, victory and defeat alike.",meaning:"The person who remains stable in all conditions — not indifferent, but unshaken — lives with true freedom.",source:"Bhagavad Gita 2.38"},
  {id:7,category:"Mind",sanskrit:"मन एव मनुष्याणां कारणं बन्धमोक्षयोः।",translation:"The mind alone is the cause of both bondage and liberation.",meaning:"The same mind that traps you in worry is the instrument of your freedom. Master the mind.",source:"Amrita Bindu Upanishad 2"},
  {id:8,category:"Devotion",sanskrit:"मन्मना भव मद्भक्तो मद्याजी मां नमस्कुरु।",translation:"Fix your mind on Me, be devoted to Me, worship Me, bow down to Me.",meaning:"Whatever you give your full attention to becomes your reality. Choose what you dedicate your mind to wisely.",source:"Bhagavad Gita 9.34"},
  {id:9,category:"Faith",sanskrit:"श्रद्धावान् लभते ज्ञानम्।",translation:"One who has faith obtains knowledge.",meaning:"Without trust in the process of learning and growth, no wisdom can take root. Faith precedes understanding.",source:"Bhagavad Gita 4.39"},
  {id:10,category:"Wisdom",sanskrit:"ज्ञानं लब्ध्वा परां शान्तिमचिरेणाधिगच्छति।",translation:"Having obtained wisdom, one quickly attains supreme peace.",meaning:"Real peace is not the absence of problems but the presence of understanding. Seek understanding first.",source:"Bhagavad Gita 4.39"},
  {id:11,category:"Action",sanskrit:"नियतं कुरु कर्म त्वं कर्म ज्यायो ह्यकर्मणः।",translation:"Perform your prescribed duties, for action is better than inaction.",meaning:"Even imperfect action is better than paralysis. Begin. The path reveals itself through movement.",source:"Bhagavad Gita 3.8"},
  {id:12,category:"Equanimity",sanskrit:"यस्त्वात्मरतिरेव स्यादात्मतृप्तश्च मानवः।",translation:"One who is satisfied in the self alone, who is content in the self — for him there is no duty.",meaning:"The person who has found fulfilment within needs nothing from the world to be complete. This is true freedom.",source:"Bhagavad Gita 3.17"},
  {id:13,category:"Courage",sanskrit:"क्लैब्यं मा स्म गमः पार्थ नैतत्त्वय्युपपद्यते।",translation:"Do not yield to impotence, O Arjuna. It does not befit you.",meaning:"When fear or self-doubt arise, remember: weakness is a choice. Your nature is strength. Rise.",source:"Bhagavad Gita 2.3"},
  {id:14,category:"Dharma",sanskrit:"स्वधर्मे निधनं श्रेयः परधर्मो भयावहः।",translation:"Better to die in one's own dharma than to live another's path — which is full of fear.",meaning:"Living someone else's life — their definition of success, their path — creates a quiet, persistent dread. Be yourself.",source:"Bhagavad Gita 3.35"},
  {id:15,category:"Surrender",sanskrit:"सर्वधर्मान्परित्यज्य मामेकं शरणं व्रज।",translation:"Abandon all varieties of dharma and simply surrender unto Me alone.",meaning:"When you have exhausted all plans and strategies, let go completely. Trust in something greater than your ego.",source:"Bhagavad Gita 18.66"},
  {id:16,category:"Knowledge",sanskrit:"न हि ज्ञानेन सदृशं पवित्रमिह विद्यते।",translation:"There is nothing in this world as purifying as knowledge.",meaning:"Knowledge — true self-knowledge — dissolves confusion, fear, and suffering more completely than any external change.",source:"Bhagavad Gita 4.38"},
  {id:17,category:"Detachment",sanskrit:"विहाय कामान्यः सर्वान् पुमांश्चरति निःस्पृहः।",translation:"One who has given up all desires and moves about without craving — that person attains peace.",meaning:"You don't have to stop wanting things. You have to stop needing them. Preference without desperation is freedom.",source:"Bhagavad Gita 2.71"},
  {id:18,category:"Giving",sanskrit:"दातव्यमिति यद्दानं दीयतेऽनुपकारिणे।",translation:"Charity given out of duty, without expectation of return — that is pure giving.",meaning:"Give because giving itself is your nature, not to receive gratitude or recognition. This purifies the heart.",source:"Bhagavad Gita 17.20"},
  {id:19,category:"Time",sanskrit:"काल: पचति भूतानि काल: संहरते प्रजाः।",translation:"Time ripens all beings; time dissolves all creation.",meaning:"Nothing lasts forever — including your current pain, struggle, or confusion. Time is both the destroyer and the healer.",source:"Mahabharata"},
  {id:20,category:"Purpose",sanskrit:"उद्धरेदात्मनात्मानं नात्मानमवसादयेत्।",translation:"Let a man lift himself by himself; let him not degrade himself.",meaning:"You are both the problem and the solution. No one can walk your path for you, but you are fully capable.",source:"Bhagavad Gita 6.5"},

  // ── UPANISHADS ─────────────────────────────────────────────────────────────
  {id:21,category:"Peace",sanskrit:"शान्तिः शान्तिः शान्तिः।",translation:"Peace — in body, mind, and spirit.",meaning:"The threefold peace invocation dissolves disturbance at every level of being: physical, mental, and spiritual.",source:"Upanishads (Shanti Patha)"},
  {id:22,category:"Self",sanskrit:"अहं ब्रह्मास्मि।",translation:"I am Brahman — I am the infinite consciousness.",meaning:"Your deepest self is not separate from universal consciousness. You are not limited by your history.",source:"Brihadaranyaka Upanishad 1.4.10"},
  {id:23,category:"Unity",sanskrit:"तत्त्वमसि।",translation:"Thou art That.",meaning:"You and the ground of all being are not two different things. Separation is the root illusion that causes suffering.",source:"Chandogya Upanishad 6.8.7"},
  {id:24,category:"Self",sanskrit:"प्रज्ञानं ब्रह्म।",translation:"Consciousness is Brahman.",meaning:"Pure awareness — not thoughts, not feelings, not the body — is the ultimate reality. You are that awareness.",source:"Aitareya Upanishad 3.3"},
  {id:25,category:"Courage",sanskrit:"उत्तिष्ठत जाग्रत प्राप्य वरान्निबोधत।",translation:"Arise, awake, and stop not until the goal is reached.",meaning:"Not enthusiasm but wakefulness. The Vedas consider inertia the greatest enemy of human potential.",source:"Katha Upanishad 1.3.14"},
  {id:26,category:"Knowledge",sanskrit:"तमसो मा ज्योतिर्गमय।",translation:"Lead me from darkness to light.",meaning:"The most fundamental human aspiration: move from ignorance toward clarity, from confusion toward understanding.",source:"Brihadaranyaka Upanishad 1.3.28"},
  {id:27,category:"Impermanence",sanskrit:"मृत्योर्मा अमृतं गमय।",translation:"Lead me from death to immortality.",meaning:"Not physical immortality — but freedom from the fear of loss, ending, and change. The deathless is within you now.",source:"Brihadaranyaka Upanishad 1.3.28"},
  {id:28,category:"Peace",sanskrit:"असतो मा सद्गमय।",translation:"Lead me from the unreal to the real.",meaning:"From the world of appearances, opinions, and fears — toward what is permanently true and steady within.",source:"Brihadaranyaka Upanishad 1.3.28"},
  {id:29,category:"Meditation",sanskrit:"एकमेवाद्वितीयम्।",translation:"One alone, without a second.",meaning:"Beneath all diversity and division is a single undivided reality. Meditation is the practice of remembering this.",source:"Chandogya Upanishad 6.2.1"},
  {id:30,category:"Self",sanskrit:"अयमात्मा ब्रह्म।",translation:"This self is Brahman.",meaning:"The very self that you think is small, limited, and separate — is in fact the infinite. Look within.",source:"Mandukya Upanishad 2"},
  {id:31,category:"Wisdom",sanskrit:"यद्यदाचरति श्रेष्ठस्तत्तदेवेतरो जनः।",translation:"Whatever a great person does, others follow.",meaning:"Leadership is not a title — it is the quality of your actions. Live the change you wish to inspire.",source:"Bhagavad Gita 3.21"},
  {id:32,category:"Mind",sanskrit:"योऽनन्तः स तदन्तः।",translation:"That which is infinite — seek it within.",meaning:"The searching mind looks outward for satisfaction. The wise mind turns inward and finds what was always there.",source:"Chandogya Upanishad"},
  {id:33,category:"Meditation",sanskrit:"ध्यानं निर्विषयं मनः।",translation:"Meditation is the mind without an object.",meaning:"When the mind stops chasing thoughts and rests in itself, that stillness is meditation. It is your natural state.",source:"Yoga Vasistha"},
  {id:34,category:"Truth",sanskrit:"सत्यं वद। धर्मं चर।",translation:"Speak truth. Walk the path of righteousness.",meaning:"Two imperatives that serve as a complete compass for any decision in modern life.",source:"Taittiriya Upanishad 1.11.1"},
  {id:35,category:"Learning",sanskrit:"स्वाध्यायान्मा प्रमदः।",translation:"Do not neglect self-study.",meaning:"The Vedic injunction to know yourself — through reading, reflection, and honest self-examination — is lifelong work.",source:"Taittiriya Upanishad 1.11.1"},
  {id:36,category:"Gratitude",sanskrit:"मातृदेवो भव। पितृदेवो भव।",translation:"Let your mother be your god. Let your father be your god.",meaning:"Honour those who gave you life and raised you. Gratitude to those who sacrificed for you is the beginning of wisdom.",source:"Taittiriya Upanishad 1.11.2"},
  {id:37,category:"Giving",sanskrit:"श्रद्धया देयम्। अश्रद्धयाऽदेयम्।",translation:"Give with faith. Give with sensitivity. Give with humility.",meaning:"The quality of your giving matters as much as the quantity. Give from fullness, not obligation.",source:"Taittiriya Upanishad 1.11.3"},
  {id:38,category:"Knowledge",sanskrit:"विज्ञानं ब्रह्म।",translation:"Pure intelligence is Brahman.",meaning:"The capacity to know, to understand, to be aware — this is your deepest nature, not your thoughts or feelings.",source:"Taittiriya Upanishad 3.1"},
  {id:39,category:"Joy",sanskrit:"आनन्दो ब्रह्म।",translation:"Bliss is Brahman.",meaning:"Joy is not a reward for achievement — it is the nature of pure awareness itself. You are made of bliss.",source:"Taittiriya Upanishad 3.6"},
  {id:40,category:"Courage",sanskrit:"अभयं प्रतिष्ठा।",translation:"Fearlessness is the foundation.",meaning:"All spiritual and material achievement rests on the willingness to act despite uncertainty. Cultivate fearlessness.",source:"Taittiriya Upanishad"},

  // ── RIGVEDA ────────────────────────────────────────────────────────────────
  {id:41,category:"Unity",sanskrit:"एकं सद्विप्रा बहुधा वदन्ति।",translation:"Truth is one; the wise call it by many names.",meaning:"No single tradition, religion, or perspective holds the complete truth. Wisdom is found in all of them.",source:"Rigveda 1.164.46"},
  {id:42,category:"Unity",sanskrit:"वसुधैव कुटुम्बकम्।",translation:"The whole world is one family.",meaning:"Your circle of compassion is meant to expand beyond tribe, nation, and faith to encompass all living beings.",source:"Maha Upanishad 6.71"},
  {id:43,category:"Peace",sanskrit:"आ नो भद्राः क्रतवो यन्तु विश्वतः।",translation:"Let noble thoughts come to us from all directions.",meaning:"Wisdom has no single source. Remain open, humble, and receptive to truth wherever it appears.",source:"Rigveda 1.89.1"},
  {id:44,category:"Gratitude",sanskrit:"अग्निमीले पुरोहितं यज्ञस्य देवमृत्विजम्।",translation:"I praise Agni, the divine fire, the priest of the sacred rite.",meaning:"The fire of consciousness, awareness, and devotion — honour it daily. Begin each day by acknowledging what lights you.",source:"Rigveda 1.1.1"},
  {id:45,category:"Nature",sanskrit:"द्यौः शान्तिरन्तरिक्षं शान्तिः पृथिवी शान्तिरापः शान्तिः।",translation:"May the sky be peaceful, the atmosphere peaceful, the earth peaceful, the waters peaceful.",meaning:"The Vedic vision of peace is ecological — it includes nature itself. Your inner peace and outer harmony are one.",source:"Yajurveda 36.17"},
  {id:46,category:"Nature",sanskrit:"माता भूमिः पुत्रोऽहं पृथिव्याः।",translation:"The Earth is my mother; I am her son.",meaning:"The Vedic relationship with nature is not ownership but kinship. We belong to the Earth; she does not belong to us.",source:"Atharvaveda 12.1.12"},
  {id:47,category:"Harmony",sanskrit:"सं गच्छध्वं सं वदध्वं सं वो मनांसि जानताम्।",translation:"Come together, speak together, let your minds be in harmony.",meaning:"Community, dialogue, and shared understanding are sacred. Division and isolation weaken the human spirit.",source:"Rigveda 10.191.2"},
  {id:48,category:"Harmony",sanskrit:"समानो मन्त्रः समितिः समानी।",translation:"Let our intentions be united; let our assembly be united.",meaning:"When people gather with shared intention and mutual respect, extraordinary things become possible.",source:"Rigveda 10.191.3"},
  {id:49,category:"Purpose",sanskrit:"तन्मे मनः शिवसङ्कल्पमस्तु।",translation:"May my mind be filled with auspicious intentions.",meaning:"Begin each day by consciously setting the quality of your intentions. The mind follows the direction you give it.",source:"Yajurveda 34.1"},
  {id:50,category:"Wisdom",sanskrit:"यत्र विश्वं भवत्येकनीडम्।",translation:"Where the whole world is as one nest.",meaning:"The Vedic vision of enlightened civilisation: a world where all beings share one home and one belonging.",source:"Rigveda 10.129"},

  // ── YOGA SUTRAS ────────────────────────────────────────────────────────────
  {id:51,category:"Mind",sanskrit:"योगश्चित्तवृत्तिनिरोधः।",translation:"Yoga is the cessation of the fluctuations of the mind.",meaning:"Yoga is not a posture. It is the art of quieting the constant noise of the thinking mind.",source:"Yoga Sutras 1.2"},
  {id:52,category:"Practice",sanskrit:"अभ्यासवैराग्याभ्यां तन्निरोधः।",translation:"The cessation of mental fluctuations is achieved through practice and non-attachment.",meaning:"Two pillars: steady practice and the willingness to let go. Neither alone is sufficient.",source:"Yoga Sutras 1.12"},
  {id:53,category:"Practice",sanskrit:"स तु दीर्घकालनैरन्तर्यसत्कारासेवितो दृढभूमिः।",translation:"Practice becomes firmly grounded when continued for a long time, without interruption, with sincere devotion.",meaning:"There are no shortcuts. The depth of transformation is proportional to the steadiness of your practice.",source:"Yoga Sutras 1.14"},
  {id:54,category:"Detachment",sanskrit:"दृष्टानुश्रविकविषयवितृष्णस्य वशीकारसंज्ञा वैराग्यम्।",translation:"Dispassion is the mastery of the one who is free from craving for objects seen or heard.",meaning:"Non-attachment is not coldness — it is the freedom to engage fully without being controlled by craving.",source:"Yoga Sutras 1.15"},
  {id:55,category:"Meditation",sanskrit:"देशबन्धश्चित्तस्य धारणा।",translation:"Dharana is the binding of the mind to a single place.",meaning:"Concentration is the first step to meditation: choose one point and return to it, again and again.",source:"Yoga Sutras 3.1"},
  {id:56,category:"Meditation",sanskrit:"तत्र प्रत्ययैकतानता ध्यानम्।",translation:"Dhyana is the continuous flow of awareness toward that object.",meaning:"When concentration deepens into an unbroken stream of attention, meditation naturally arises.",source:"Yoga Sutras 3.2"},
  {id:57,category:"Ethics",sanskrit:"अहिंसासत्यास्तेयब्रह्मचर्यापरिग्रहा यमाः।",translation:"Non-violence, truthfulness, non-stealing, continence, non-possessiveness — these are the restraints.",meaning:"The five Yamas are the ethical foundation of all spiritual practice. Without them, no meditation technique will work.",source:"Yoga Sutras 2.30"},
  {id:58,category:"Practice",sanskrit:"शौचसन्तोषतपःस्वाध्यायेश्वरप्रणिधानानि नियमाः।",translation:"Purity, contentment, discipline, self-study, and surrender — these are the observances.",meaning:"The five Niyamas are daily habits that build the inner environment where wisdom naturally grows.",source:"Yoga Sutras 2.32"},
  {id:59,category:"Equanimity",sanskrit:"सुखानुशयी रागः।",translation:"Attachment is that which follows pleasure.",meaning:"We become addicted to pleasurable experiences and then suffer in their absence. Notice this pattern.",source:"Yoga Sutras 2.7"},
  {id:60,category:"Detachment",sanskrit:"दुःखानुशयी द्वेषः।",translation:"Aversion is that which follows pain.",meaning:"We avoid what was once painful and miss opportunities because of old wounds. Recognise your aversions.",source:"Yoga Sutras 2.8"},

  // ── BHAGAVAD GITA (continued) ──────────────────────────────────────────────
  {id:61,category:"Service",sanskrit:"श्रेयान्स्वधर्मो विगुणः परधर्मात्स्वनुष्ठितात्।",translation:"Better is one's own dharma imperfectly performed than the dharma of another performed perfectly.",meaning:"An imperfect version of your own authentic path is worth more than a perfect imitation of someone else's.",source:"Bhagavad Gita 18.47"},
  {id:62,category:"Food",sanskrit:"आयुःसत्त्वबलारोग्यसुखप्रीतिविवर्धनाः।",translation:"Foods that increase lifespan, purity, strength, health, joy, and cheerfulness are dear to the sattvic.",meaning:"What you eat affects not just your body but your clarity of mind and emotional stability. Choose consciously.",source:"Bhagavad Gita 17.8"},
  {id:63,category:"Purpose",sanskrit:"एष तव श्रेयस्करो लोके।",translation:"This is truly beneficial for you in the world.",meaning:"True benefit is not what feels good now but what serves your growth, your relationships, and your highest self.",source:"Mahabharata"},
  {id:64,category:"Surrender",sanskrit:"ईश्वरः सर्वभूतानां हृद्देशेऽर्जुन तिष्ठति।",translation:"The Lord dwells in the hearts of all beings.",meaning:"Divinity is not distant — it is present in the core of every being, including you. You are never abandoned.",source:"Bhagavad Gita 18.61"},
  {id:65,category:"Wisdom",sanskrit:"नादत्ते कस्यचित्पापं न चैव सुकृतं विभुः।",translation:"The Supreme neither accepts the sin nor the virtue of anyone.",meaning:"You are responsible for your choices. No power outside you distributes fortune or misfortune arbitrarily.",source:"Bhagavad Gita 5.15"},
  {id:66,category:"Knowledge",sanskrit:"यदा ते मोहकलिलं बुद्धिर्व्यतितरिष्यति।",translation:"When your mind crosses the thicket of delusion, then you will be indifferent to all that has been heard.",meaning:"Beyond the confusion of conflicting advice and opinions, your own clarity will emerge — trust the process.",source:"Bhagavad Gita 2.52"},
  {id:67,category:"Equanimity",sanskrit:"दुःखेष्वनुद्विग्नमनाः सुखेषु विगतस्पृहः।",translation:"One who is not disturbed in mind even amidst the threefold miseries — who is not elated when there is happiness.",meaning:"Equanimity is not emotional numbness — it is a stable centre from which you can engage everything fully.",source:"Bhagavad Gita 2.56"},
  {id:68,category:"Mind",sanskrit:"चञ्चलं हि मनः कृष्ण प्रमाथि बलवद्दृढम्।",translation:"The mind is restless, turbulent, strong, and obstinate.",meaning:"Arjuna's complaint is every human's complaint. The first step to mastering the mind is acknowledging its nature.",source:"Bhagavad Gita 6.34"},
  {id:69,category:"Mind",sanskrit:"अभ्यासेन तु कौन्तेय वैराग्येण च गृह्यते।",translation:"By practice and by detachment, the mind can be controlled.",meaning:"Krishna's answer: you cannot suppress the mind, but you can train it with patient practice and non-grasping.",source:"Bhagavad Gita 6.35"},
  {id:70,category:"Joy",sanskrit:"विद्याविनयसम्पन्ने ब्राह्मणे गवि हस्तिनि।",translation:"The wise see with equal vision a learned brahmin, a cow, an elephant, a dog, and an outcast.",meaning:"True wisdom removes the hierarchical filters through which we see people. Everyone deserves equal dignity.",source:"Bhagavad Gita 5.18"},
  {id:71,category:"Letting Go",sanskrit:"जातस्य हि ध्रुवो मृत्युर्ध्रुवं जन्म मृतस्य च।",translation:"For one who is born, death is certain; and for one who is dead, birth is certain.",meaning:"Clinging to permanence causes suffering. When you accept the cycle of change, you find peace in impermanence.",source:"Bhagavad Gita 2.27"},
  {id:72,category:"Service",sanskrit:"सहयज्ञाः प्रजाः सृष्ट्वा पुरोवाच प्रजापतिः।",translation:"In the beginning, the Creator created humanity along with the spirit of mutual aid.",meaning:"You were not created to be self-sufficient in isolation. Collaboration and service are woven into human nature.",source:"Bhagavad Gita 3.10"},
  {id:73,category:"Leadership",sanskrit:"यद्यदाचरति श्रेष्ठस्तत्तदेवेतरो जनः।",translation:"Whatever a great person does, common people follow.",meaning:"You don't need a title to lead. The quality of your conduct is your greatest influence on others.",source:"Bhagavad Gita 3.21"},
  {id:74,category:"Nature",sanskrit:"पत्रं पुष्पं फलं तोयं यो मे भक्त्या प्रयच्छति।",translation:"Whoever offers Me with devotion a leaf, a flower, a fruit, or water — I accept.",meaning:"Even the simplest offering, given with genuine love and attention, has infinite value. Devotion is not about scale.",source:"Bhagavad Gita 9.26"},
  {id:75,category:"Courage",sanskrit:"हतो वा प्राप्स्यसि स्वर्गं जित्वा वा भोक्ष्यसे महीम्।",translation:"If you die in battle, you will attain heaven; if you win, you will enjoy the earth.",meaning:"In any righteous endeavour, both outcomes have value. The effort itself has merit regardless of results.",source:"Bhagavad Gita 2.37"},
  {id:76,category:"Detachment",sanskrit:"न कर्तृत्वं न कर्माणि लोकस्य सृजति प्रभुः।",translation:"The Supreme does not create agency, nor actions, nor the union of action and result.",meaning:"You are the author of your choices. No force outside you is responsible for where you are today.",source:"Bhagavad Gita 5.14"},
  {id:77,category:"Wisdom",sanskrit:"येषां न्तगतं पापं जनानां पुण्यकर्मणाम्।",translation:"Those whose sins have been destroyed by virtuous actions — free from the delusion of duality — worship Me.",meaning:"As you act with greater integrity and wisdom, the mental noise of guilt, shame, and confusion naturally diminishes.",source:"Bhagavad Gita 7.28"},
  {id:78,category:"Purpose",sanskrit:"मयि सर्वाणि कर्माणि संन्यस्याध्यात्मचेतसा।",translation:"Offer all actions to Me, with a mind fixed on the self, free from desire and the sense of mine.",meaning:"Act in service of something larger than personal gain. When the ego is not the reference point, action becomes free.",source:"Bhagavad Gita 3.30"},
  {id:79,category:"Faith",sanskrit:"ये यथा मां प्रपद्यन्ते तांस्तथैव भजाम्यहम्।",translation:"As people surrender to Me, I reward them accordingly.",meaning:"Life responds to the quality of your engagement. Show up fully, and the universe meets you at that level.",source:"Bhagavad Gita 4.11"},
  {id:80,category:"Time",sanskrit:"अव्यक्तोऽयमचिन्त्योऽयमविकार्योऽयमुच्यते।",translation:"The soul is unmanifest, unthinkable, and unchanging.",meaning:"Behind all the changes of your life — the gains, losses, and transformations — your core remains untouched.",source:"Bhagavad Gita 2.25"},

  // ── CHANAKYA / ARTHASHASTRA / NITISHASTRA ──────────────────────────────────
  {id:81,category:"Wisdom",sanskrit:"विद्या विनयेन शोभते।",translation:"Knowledge is beautified by humility.",meaning:"The more one knows, the more one recognises the vastness of the unknown. Humility is the hallmark of wisdom.",source:"Hitopadesa"},
  {id:82,category:"Leadership",sanskrit:"सुखस्य मूलं धर्मः।",translation:"The root of happiness is Dharma.",meaning:"Ethics is not a constraint on success — it is its deepest foundation. Unethical success always collapses.",source:"Chanakya Niti"},
  {id:83,category:"Learning",sanskrit:"विद्वान्सर्वत्र पूज्यते।",translation:"A learned person is honoured everywhere.",meaning:"True knowledge is the one wealth that cannot be stolen, taxed, or taken from you. Invest in learning.",source:"Chanakya Niti"},
  {id:84,category:"Time",sanskrit:"काल एव करोति संहारम्।",translation:"Time alone brings about dissolution.",meaning:"Do not be too attached to any situation — good or bad. Time is the great equaliser.",source:"Mahabharata"},
  {id:85,category:"Relationships",sanskrit:"सन्तोषस्त्रिषु कर्तव्यः स्वदारे भोजने धने।",translation:"Contentment should be practiced in three things: with one's spouse, food, and wealth.",meaning:"Comparing your relationships, meals, and income to others breeds permanent dissatisfaction. Practise contentment.",source:"Chanakya Niti"},
  {id:86,category:"Leadership",sanskrit:"यस्य नास्ति स्वयं प्रज्ञा शास्त्रं तस्य करोति किम्।",translation:"What can scripture do for one who lacks self-wisdom?",meaning:"No amount of information substitutes for genuine self-awareness. All knowledge must be filtered through inquiry.",source:"Chanakya Niti"},
  {id:87,category:"Relationships",sanskrit:"को हि भारः समर्थानां किं दूरं व्यवसायिनाम्।",translation:"What is heavy for the capable? What is distant for the determined?",meaning:"Capability and determination dissolve what seems impossible. Develop both through consistent effort.",source:"Hitopadesa"},
  {id:88,category:"Dharma",sanskrit:"धर्म एव हतो हन्ति धर्मो रक्षति रक्षितः।",translation:"Dharma destroyed destroys; Dharma protected protects.",meaning:"Living with integrity is not just moral — it is protective. Abandon your values and you unravel from within.",source:"Manusmriti 8.15"},
  {id:89,category:"Wealth",sanskrit:"अर्थस्य पुरुषो दासः।",translation:"Man is a slave to wealth.",meaning:"When money becomes your master rather than your servant, your freedom is sold. Seek enough, not excess.",source:"Mahabharata"},
  {id:90,category:"Health",sanskrit:"आरोग्यं परमं भाग्यम्।",translation:"Good health is the greatest fortune.",meaning:"Before any ambition, achievement, or pleasure — health is the foundation. Protect it as your primary asset.",source:"Chanakya Niti"},
  {id:91,category:"Friendship",sanskrit:"विनाशकाले विपरीतबुद्धिः।",translation:"At the time of destruction, the intellect becomes perverse.",meaning:"When we are about to make our worst decisions, our minds often feel most certain. Pause in moments of strong emotion.",source:"Mahabharata"},
  {id:92,category:"Leadership",sanskrit:"राजा कालस्य कारणम्।",translation:"The leader is the cause of the times.",meaning:"Leadership shapes the environment. Those who lead — a team, a family, a community — are responsible for its culture.",source:"Chanakya Niti"},
  {id:93,category:"Learning",sanskrit:"अनुभवः परमो गुरुः।",translation:"Experience is the highest teacher.",meaning:"Books and lectures point the way, but lived experience — including failure — is where real understanding is forged.",source:"Chanakya Niti"},
  {id:94,category:"Patience",sanskrit:"क्षमा शस्त्रमहिंसकस्य।",translation:"Forgiveness is the weapon of the non-violent.",meaning:"Patience and forgiveness are not weakness — they are the most powerful responses to provocation.",source:"Mahabharata"},
  {id:95,category:"Truth",sanskrit:"सत्यमेव जयते।",translation:"Truth alone triumphs.",meaning:"India's national motto. In the long arc of time, honesty and integrity outlast all deception and manipulation.",source:"Mundaka Upanishad 3.1.6"},
  {id:96,category:"Giving",sanskrit:"परोपकाराय फलन्ति वृक्षाः।",translation:"Trees bear fruit for others; rivers flow for others.",meaning:"Nature exists in a cycle of giving. The person who gives freely — time, knowledge, care — lives most fully.",source:"Subhashitani"},
  {id:97,category:"Patience",sanskrit:"धैर्यं सर्वत्र साधनम्।",translation:"Patience is the means to everything.",meaning:"No worthy goal is achieved quickly. The willingness to persist through discomfort is the decisive factor.",source:"Chanakya Niti"},
  {id:98,category:"Friendship",sanskrit:"मित्रं प्राप्नोति सत्कर्मभिः।",translation:"True friendship is gained through good deeds.",meaning:"Lasting relationships are built not through charm or manipulation but through consistent trustworthy behaviour.",source:"Hitopadesa"},
  {id:99,category:"Mind",sanskrit:"मनसैव जगज्जयेत्।",translation:"Conquer the world with the mind.",meaning:"External circumstances follow internal states. Master your mind and your outer life begins to align.",source:"Yoga Vasistha"},
  {id:100,category:"Purpose",sanskrit:"सर्वे भवन्तु सुखिनः।",translation:"May all beings be happy.",meaning:"The highest purpose is not personal happiness but the wellbeing of all. Begin with this intention each day.",source:"Brihadaranyaka Upanishad 1.4.14"},

  // ── MAHABHARATA / VIDURA NITI ──────────────────────────────────────────────
  {id:101,category:"Wisdom",sanskrit:"अयं निजः परो वेति गणना लघुचेतसाम्।",translation:"Mine or another's — such calculation is for small minds. For the magnanimous, the whole world is family.",meaning:"Generosity of spirit — the willingness to see all as kin — is the mark of true greatness.",source:"Maha Upanishad 6.71"},
  {id:102,category:"Patience",sanskrit:"न कोपः सिद्धिमाप्नोति।",translation:"Anger does not lead to success.",meaning:"Acting from anger rarely produces the outcome you want. The pause between stimulus and response is where wisdom lives.",source:"Mahabharata"},
  {id:103,category:"Truth",sanskrit:"सत्यं ब्रूयात् प्रियं ब्रूयान्न ब्रूयात् सत्यमप्रियम्।",translation:"Speak the truth; speak pleasantly. Do not speak the truth unpleasantly.",meaning:"Honesty without compassion is cruelty. Speak truthfully, but with the intention to help, not to wound.",source:"Manusmriti 4.138"},
  {id:104,category:"Dharma",sanskrit:"धर्मो रक्षति रक्षितः।",translation:"Dharma protects those who protect it.",meaning:"Live with integrity consistently — even when inconvenient — and it becomes a force that protects your life.",source:"Mahabharata"},
  {id:105,category:"Letting Go",sanskrit:"यद्भावि न तद्भावि।",translation:"What is not destined to happen will not happen.",meaning:"Some things are beyond your control. Exhausting yourself against the fixed is the source of deep suffering.",source:"Mahabharata"},
  {id:106,category:"Action",sanskrit:"उद्यमेन हि सिध्यन्ति कार्याणि न मनोरथैः।",translation:"Goals are achieved through effort, not through wishful thinking.",meaning:"Intention without action is fantasy. The universe rewards movement, not merely good ideas.",source:"Hitopadesa"},
  {id:107,category:"Self",sanskrit:"आत्मनः प्रतिकूलानि परेषां न समाचरेत्।",translation:"Do not do to others what is disagreeable to yourself.",meaning:"The Vedic Golden Rule, predating many other traditions. Empathy is the foundation of ethical life.",source:"Mahabharata"},
  {id:108,category:"Impermanence",sanskrit:"न किञ्चिदपि तिष्ठति।",translation:"Nothing whatsoever remains unchanged.",meaning:"Clinging to people, states, and situations that must change is the source of all suffering. Flow with life.",source:"Mahabharata"},
  {id:109,category:"Leadership",sanskrit:"प्रजासुखे सुखं राज्ञः प्रजानां च हिते हितम्।",translation:"In the happiness of the subjects lies the king's happiness; in their welfare, his welfare.",meaning:"True leadership is measured by the flourishing of those you serve — not by your own prestige or power.",source:"Arthashastra 1.19.34"},
  {id:110,category:"Wealth",sanskrit:"संतोषमूलं सुखम्।",translation:"Contentment is the root of happiness.",meaning:"The pursuit of more — wealth, status, experience — has no natural end. Contentment is a practice, not a destination.",source:"Mahabharata"},

  // ── RAMAYANA INSPIRED ──────────────────────────────────────────────────────
  {id:111,category:"Dharma",sanskrit:"रामो विग्रहवान् धर्मः।",translation:"Rama is Dharma in human form.",meaning:"Your highest self — ethical, compassionate, courageous, devoted — is not an aspiration but your essential nature.",source:"Valmiki Ramayana"},
  {id:112,category:"Relationships",sanskrit:"न त्वहं कामये राज्यं न स्वर्गं न पुनर्भवम्।",translation:"I do not desire a kingdom, nor heaven, nor freedom from rebirth.",meaning:"True love desires nothing for the self — only the wellbeing of the beloved. This is the Vedic ideal of love.",source:"Valmiki Ramayana"},
  {id:113,category:"Courage",sanskrit:"भय हारत हिय हारत सोई।",translation:"Only one who overcomes fear truly wins.",meaning:"Courage is not the absence of fear but the decision that something else matters more than your fear.",source:"Ramcharitmanas"},
  {id:114,category:"Service",sanskrit:"परहित सरिस धरम नहिं भाई।",translation:"There is no dharma equal to serving others.",meaning:"In Tulsidas's words: service to others is the highest spiritual practice. It is available in every moment.",source:"Ramcharitmanas"},
  {id:115,category:"Giving",sanskrit:"जो दूसरों के लिए जीता है वो अमर होता है।",translation:"One who lives for others becomes immortal.",meaning:"The legacy of a life well-lived is measured in what you gave, not what you accumulated.",source:"Inspired by Vedic tradition"},

  // ── PURANAS / STORIES ──────────────────────────────────────────────────────
  {id:116,category:"Purpose",sanskrit:"जीवो जीवस्य जीवनम्।",translation:"One life is the sustenance of another.",meaning:"All of life is interdependent. Your existence is held up by countless other beings. Act with this awareness.",source:"Bhagavata Purana 1.13.47"},
  {id:117,category:"Devotion",sanskrit:"नारायणः परो देवः।",translation:"Narayana — the one in whom all beings rest — is the supreme divine.",meaning:"The divine is not distant or separate. It is the very ground of being in which all existence is held.",source:"Bhagavata Purana"},
  {id:118,category:"Time",sanskrit:"कालो ह्ययं निरवधिर्विभवश्च साध्यः।",translation:"Time is endless; its resources are inexhaustible.",meaning:"Do not succumb to urgency and scarcity thinking. Time, used well, is sufficient for everything that truly matters.",source:"Bhagavata Purana"},
  {id:119,category:"Impermanence",sanskrit:"यः स्यात्स सर्वभावानाम् प्रभवश्चाप्ययः।",translation:"That from which all beings arise and into which they return.",meaning:"Everything you experience — joy, pain, achievement, loss — arises from and returns to the same source. Rest in that source.",source:"Bhagavata Purana"},
  {id:120,category:"Joy",sanskrit:"यं लब्ध्वा चापरं लाभं मन्यते नाधिकं ततः।",translation:"Having gained that, one thinks there is no greater gain.",meaning:"There exists a joy so complete that nothing else seems more worth having. This is the promise of self-knowledge.",source:"Bhagavad Gita 6.22"},

  // ── NARADA BHAKTI SUTRAS ───────────────────────────────────────────────────
  {id:121,category:"Devotion",sanskrit:"सा त्वस्मिन् परमप्रेमरूपा।",translation:"Bhakti is of the nature of supreme love for the Divine.",meaning:"The highest form of devotion is not ritual but pure, unconditional love — for life itself, for others, for the sacred.",source:"Narada Bhakti Sutras 2"},
  {id:122,category:"Devotion",sanskrit:"अमृतस्वरूपा च।",translation:"And it is of the nature of immortality.",meaning:"Love, when it is truly unconditional, transcends the fear of death and loss. It is the taste of the infinite.",source:"Narada Bhakti Sutras 3"},
  {id:123,category:"Purpose",sanskrit:"लोकेऽपि भगवद्गुणश्रवणकीर्तनात्।",translation:"Even in the world, devotion grows through hearing and singing the divine qualities.",meaning:"What you repeatedly give your attention to shapes your character. Fill your mind with what you wish to become.",source:"Narada Bhakti Sutras 37"},
  {id:124,category:"Friendship",sanskrit:"तत्र सहजवासनानां निरोधो भवति।",translation:"In the company of the wise, natural tendencies are transformed.",meaning:"You become like those you spend time with. Choose your companions as carefully as you choose your food.",source:"Narada Bhakti Sutras"},
  {id:125,category:"Letting Go",sanskrit:"न तद्विहाय केनापि किञ्चित् कर्तव्यम्।",translation:"Without that love, nothing else is truly worth doing.",meaning:"When love for what is highest is present, all other actions become aligned and purposeful.",source:"Narada Bhakti Sutras"},

  // ── VIVEKACHUDAMANI (ADI SHANKARACHARYA) ──────────────────────────────────
  {id:126,category:"Self",sanskrit:"ब्रह्म सत्यं जगन्मिथ्या।",translation:"Brahman is real; the world is illusion.",meaning:"Not that the world doesn't exist — but that you mistake its nature. See through appearances to the reality beneath.",source:"Vivekachudamani"},
  {id:127,category:"Wisdom",sanskrit:"जीवो ब्रह्मैव नापरः।",translation:"The individual self is none other than Brahman.",meaning:"The separation between the small self and the infinite is conceptual, not real. You are already what you seek.",source:"Vivekachudamani"},
  {id:128,category:"Knowledge",sanskrit:"विवेको विमुक्तिहेतुः।",translation:"Discrimination is the cause of liberation.",meaning:"The ability to discern what is real from what is false, what is permanent from what is transient — this is wisdom.",source:"Vivekachudamani"},
  {id:129,category:"Detachment",sanskrit:"वैराग्यं मुमुक्षुत्वं च।",translation:"Dispassion and the desire for liberation — these are the qualifications.",meaning:"You need only two things: the willingness to let go of what doesn't serve you, and a genuine longing for freedom.",source:"Vivekachudamani"},
  {id:130,category:"Self",sanskrit:"त्वमेव तत् सर्वमसि प्रसिद्धम्।",translation:"You yourself are that well-known ultimate reality.",meaning:"The answer to every search is not somewhere to be found — it is what is doing the searching.",source:"Vivekachudamani"},

  // ── YOGA VASISTHA ──────────────────────────────────────────────────────────
  {id:131,category:"Mind",sanskrit:"मनोमात्रं जगत्।",translation:"The world is nothing but mind.",meaning:"Your experience of life is filtered entirely through your mind. Change the quality of your mind and the world changes.",source:"Yoga Vasistha"},
  {id:132,category:"Action",sanskrit:"पुरुषार्थेन विना भाग्यं न सिध्यति।",translation:"Without personal effort, fate does not succeed.",meaning:"Destiny is not a fixed track. It is shaped by the quality and consistency of your efforts.",source:"Yoga Vasistha"},
  {id:133,category:"Practice",sanskrit:"अभ्यासयोगेन ततो मामिच्छाप्तुं धनञ्जय।",translation:"By the yoga of constant practice, seek to reach Me, O Arjuna.",meaning:"No insight, no matter how profound, replaces daily practice. Understanding without application is incomplete.",source:"Bhagavad Gita 12.9"},
  {id:134,category:"Wisdom",sanskrit:"स्वयं ज्ञातव्यमात्मानम्।",translation:"The self must be known by oneself.",meaning:"No teacher, book, or technique can give you self-knowledge. They can only point. The knowing is always yours.",source:"Yoga Vasistha"},
  {id:135,category:"Letting Go",sanskrit:"यद्भावि भवत्येव।",translation:"What is destined will surely come to pass.",meaning:"Some events are beyond your control. Accepting this is not resignation — it is the beginning of real peace.",source:"Yoga Vasistha"},

  // ── DEVI MAHATMYAM / SHAKTA TRADITION ─────────────────────────────────────
  {id:136,category:"Courage",sanskrit:"या देवी सर्वभूतेषु शक्तिरूपेण संस्थिता।",translation:"The goddess who dwells in all beings as power and energy.",meaning:"The creative force — Shakti — is not external. It lives within you as potential, as capacity, as life itself.",source:"Devi Mahatmyam 5.9"},
  {id:137,category:"Self",sanskrit:"या देवी सर्वभूतेषु चेतनेत्यभिधीयते।",translation:"She who dwells in all beings as consciousness.",meaning:"Consciousness is not your possession — it is what you are. This recognition dissolves the fear of unworthiness.",source:"Devi Mahatmyam 5.14"},
  {id:138,category:"Peace",sanskrit:"या देवी सर्वभूतेषु शान्तिरूपेण संस्थिता।",translation:"The goddess who dwells in all beings as peace.",meaning:"Peace is not a state to achieve — it is your underlying nature, temporarily obscured by noise and reactivity.",source:"Devi Mahatmyam 5.11"},
  {id:139,category:"Wisdom",sanskrit:"या देवी सर्वभूतेषु बुद्धिरूपेण संस्थिता।",translation:"She who dwells in all beings as intelligence.",meaning:"The capacity to know, to understand, to discern — this intelligence is not yours but flows through you from the infinite.",source:"Devi Mahatmyam 5.15"},
  {id:140,category:"Devotion",sanskrit:"त्वं स्वाहा त्वं स्वधा त्वं हि वषट्कारः।",translation:"You are the sacred offering; you are the ancestor's gift; you are the sacred call.",meaning:"The divine is not separate from the sacred acts of life — eating, honouring ancestors, ritual. Life itself is the offering.",source:"Devi Mahatmyam 1.73"},

  // ── ASHTAVAKRA GITA ────────────────────────────────────────────────────────
  {id:141,category:"Self",sanskrit:"न त्वं देहो न ते देहो भोक्ता कर्ता न वा भवान्।",translation:"You are not the body; the body is not yours. You are not the doer, nor the enjoyer.",meaning:"You are the witness — pure awareness — not the character in the story. This recognition is the beginning of freedom.",source:"Ashtavakra Gita 1.3"},
  {id:142,category:"Freedom",sanskrit:"मुक्तिमिच्छसि चेत्तात विषयान् विषवत् त्यज।",translation:"If you desire liberation, renounce sense objects as poison.",meaning:"Not all pleasures are equal in their consequences. Choose experiences that expand your awareness rather than contract it.",source:"Ashtavakra Gita 1.2"},
  {id:143,category:"Self",sanskrit:"चिन्मात्रोऽहमिति ज्ञात्वा मा खेदं भोक्तुमर्हसि।",translation:"Knowing yourself as pure consciousness, do not grieve.",meaning:"When you remember what you truly are, the weight of personal history and future anxiety dissolves.",source:"Ashtavakra Gita 15.1"},
  {id:144,category:"Equanimity",sanskrit:"सुखदुःखे जन्ममृत्यू लाभालाभावुभे समम्।",translation:"Pleasure and pain, birth and death, gain and loss — treat them all the same.",meaning:"The one who is not thrown by either good or bad fortune has found the ground that cannot be shaken.",source:"Ashtavakra Gita"},
  {id:145,category:"Freedom",sanskrit:"बाह्यस्पर्शेषु असक्तात्मा विन्दत्यात्मनि यत् सुखम्।",translation:"The one unattached to external things discovers the joy that is in the self.",meaning:"The joy available within you — through stillness, breath, and awareness — is deeper than anything the world provides.",source:"Bhagavad Gita 5.21"},

  // ── TIRUKKURAL ─────────────────────────────────────────────────────────────
  {id:146,category:"Dharma",sanskrit:"அறனெனப் படுவது யாதெனின் யாதொன்றும் பிறர்நோவ செய்யாமை நிறுத்தல்.",translation:"What is dharma? It is to refrain from doing to others what you know would harm yourself.",meaning:"The simplest ethical test: before any action, ask if you would want it done to you.",source:"Tirukkural 316"},
  {id:147,category:"Learning",sanskrit:"கற்றதனால் ஆய பயனென்கொல் வாலறிவன் நற்றாள் தொழாவிடின்.",translation:"What profit is gained from learning if one does not bow to the feet of the truly wise?",meaning:"Knowledge without humility and reverence is arrogance dressed as education.",source:"Tirukkural 2"},
  {id:148,category:"Patience",sanskrit:"நிலத்தியல்பால் நீர்திரிந் தற்றாகும் மாந்தர்க்கு இனத்தியல்பே யாகும் இயல்பு.",translation:"As water changes according to the soil through which it flows, a person's character is shaped by their companions.",meaning:"Your environment — physical and social — shapes who you become. Choose carefully.",source:"Tirukkural 452"},
  {id:149,category:"Giving",sanskrit:"ஈதல் இசைபட வாழ்தல் அதுவல்லது ஊதியம் இல்லை உயிர்க்கு.",translation:"To live in a way that is worthy of praise and to give — this alone is the profit of living.",meaning:"A life of generosity and good reputation is the highest return on the investment of being alive.",source:"Tirukkural 231"},
  {id:150,category:"Truth",sanskrit:"வாய்மை எனப்படுவது யாதெனின் யாதொன்றும் தீமை இலாத சொலல்.",translation:"What is called truth? It is words that are free from all harm.",meaning:"Truth is not just factual accuracy — it is speech that does not injure. Harmless truthfulness.",source:"Tirukkural 291"},

  // ── KABIR / SANT TRADITION ─────────────────────────────────────────────────
  {id:151,category:"Self",sanskrit:"मोको कहाँ ढूंढे रे बंदे, मैं तो तेरे पास में।",translation:"Where do you search for Me? I am right here beside you.",meaning:"The divine you seek in temples, rituals, and pilgrimages is present within you, here, now.",source:"Kabir"},
  {id:152,category:"Present",sanskrit:"कल करे सो आज कर, आज करे सो अब।",translation:"What you plan for tomorrow, do today. What you plan for today, do now.",meaning:"The present moment is the only place where action is possible. Tomorrow is always one day away.",source:"Kabir"},
  {id:153,category:"Wisdom",sanskrit:"बुरा जो देखन मैं चला, बुरा न मिलिया कोय।\nजो दिल खोजा आपना, मुझसे बुरा न कोय।",translation:"When I went looking for the bad in others, I found none. When I searched my own heart, I found none worse than me.",meaning:"Judgment of others is often a mirror. The flaws we readily see outside often live within us too.",source:"Kabir"},
  {id:154,category:"Impermanence",sanskrit:"माटी कहे कुम्हार से, तू क्या रौंदे मोय।\nएक दिन ऐसा होगा, मैं रौंदूँगी तोय।",translation:"The clay says to the potter: why do you trample me? One day I will trample you.",meaning:"Humility before nature and time. All that we build with earth will return to earth.",source:"Kabir"},
  {id:155,category:"Present",sanskrit:"जो है सो अभिही है, जो नहीं वो कबहूँ नहिं।",translation:"What is, is right now. What is not, will never be.",meaning:"Reality is always only now. Your suffering about the past and anxiety about the future are both imaginary.",source:"Kabir"},

  // ── MIRABAI / BHAKTI TRADITION ─────────────────────────────────────────────
  {id:156,category:"Devotion",sanskrit:"मेरे तो गिरिधर गोपाल, दूसरो न कोई।",translation:"My only one is the divine; there is none other for me.",meaning:"Single-pointed devotion — giving yourself entirely to what you love most — is the path to complete fulfilment.",source:"Mirabai"},
  {id:157,category:"Joy",sanskrit:"पायो जी मैंने राम रतन धन पायो।",translation:"I have found it — the precious jewel of the divine name.",meaning:"There is a joy available through inner realisation that no material success can match. Seek what doesn't perish.",source:"Mirabai"},

  // ── ISHA UPANISHAD ─────────────────────────────────────────────────────────
  {id:158,category:"Unity",sanskrit:"ईशा वास्यमिदं सर्वं यत्किञ्च जगत्यां जगत्।",translation:"All this — whatever exists in this changing universe — is pervaded by the Lord.",meaning:"The divine is not somewhere else — it is the very fabric of existence. Treat everything accordingly.",source:"Isha Upanishad 1"},
  {id:159,category:"Detachment",sanskrit:"तेन त्यक्तेन भुञ्जीथाः मा गृधः कस्यस्विद्धनम्।",translation:"Enjoy what is given to you through renunciation; do not covet the wealth of anyone.",meaning:"Enjoy life fully — but hold nothing as 'mine' with white-knuckle possession. Receive, enjoy, release.",source:"Isha Upanishad 1"},
  {id:160,category:"Action",sanskrit:"कुर्वन्नेवेह कर्माणि जिजीविषेत् शतं समाः।",translation:"One should wish to live a hundred years — engaged in action.",meaning:"Life is not for withdrawal from the world but for engaged, purposeful action within it. Live fully.",source:"Isha Upanishad 2"},

  // ── MUNDAKA UPANISHAD ──────────────────────────────────────────────────────
  {id:161,category:"Truth",sanskrit:"सत्यमेव जयते नानृतम्।",translation:"Truth alone triumphs, not falsehood.",meaning:"In the short term, deception may seem to succeed. In the long arc of time, only truth stands.",source:"Mundaka Upanishad 3.1.6"},
  {id:162,category:"Knowledge",sanskrit:"परीक्ष्य लोकान् कर्मचितान् ब्राह्मणो।",translation:"Having examined all worlds won by action, let the wise seek what is not made by action.",meaning:"All external achievements are temporary. Seek the one thing that cannot be taken — self-knowledge.",source:"Mundaka Upanishad 1.2.12"},
  {id:163,category:"Wisdom",sanskrit:"द्वे विद्ये वेदितव्ये।",translation:"There are two kinds of knowledge to be known — the lower and the higher.",meaning:"Lower knowledge is information about the world. Higher knowledge is the direct knowing of the self. Both are needed.",source:"Mundaka Upanishad 1.1.4"},

  // ── KENA UPANISHAD ─────────────────────────────────────────────────────────
  {id:164,category:"Self",sanskrit:"यस्य अमतं तस्य मतम् मतं यस्य न वेद सः।",translation:"Those who think they know It do not know It; those who know they do not know It, know It.",meaning:"The deepest reality cannot be grasped by the thinking mind. It can only be recognised through stillness.",source:"Kena Upanishad 2.3"},
  {id:165,category:"Knowledge",sanskrit:"न तत्र चक्षुर्गच्छति न वाग्गच्छति नो मनः।",translation:"The eye does not go there, nor speech, nor mind.",meaning:"The ultimate reality cannot be perceived by the senses or conceived by the mind. It perceives through us.",source:"Kena Upanishad 1.3"},

  // ── PRASHNA UPANISHAD ──────────────────────────────────────────────────────
  {id:166,category:"Breath",sanskrit:"प्राणो ह वै वायुः।",translation:"Prana is indeed breath.",meaning:"Life force flows through breath. To regulate breath is to regulate energy, emotion, and attention.",source:"Prashna Upanishad 2.3"},
  {id:167,category:"Health",sanskrit:"प्राणो ह सर्वं भूतं।",translation:"Prana is all living beings.",meaning:"The life force that animates you is the same that animates all of nature. You are not separate from life.",source:"Prashna Upanishad 2.13"},

  // ── MANDUKYA UPANISHAD ─────────────────────────────────────────────────────
  {id:168,category:"Self",sanskrit:"सर्वं ह्येतद् ब्रह्म।",translation:"All this is indeed Brahman.",meaning:"Not just you — but everything you see, hear, taste, and touch is an expression of the one consciousness.",source:"Mandukya Upanishad 2"},
  {id:169,category:"Meditation",sanskrit:"ओम् इत्येतदक्षरम् इदं सर्वम्।",translation:"Om — this syllable is all this.",meaning:"The primordial sound OM is said to contain the vibration of the entire universe. Begin meditation here.",source:"Mandukya Upanishad 1"},

  // ── SWAMI VIVEKANANDA INSPIRED ─────────────────────────────────────────────
  {id:170,category:"Courage",sanskrit:"शक्तिमान् भव।",translation:"Be strong.",meaning:"Vivekananda's core message: strength is the basis of all virtue. Weakness, not sin, is the source of most evil.",source:"Inspired by Swami Vivekananda"},
  {id:171,category:"Service",sanskrit:"शिवज्ञानेन जीवसेवा।",translation:"Serve the human as the divine.",meaning:"True service is not charity from superiority — it is worship of the divine in every person you serve.",source:"Inspired by Ramakrishna"},
  {id:172,category:"Self",sanskrit:"आत्मनो मोक्षार्थं जगद्धिताय च।",translation:"For one's own liberation and for the welfare of the world.",meaning:"Personal growth and service to the world are not in conflict — they are the same path.",source:"Ramakrishna Mission motto"},

  // ── PATANJALI (extended) ───────────────────────────────────────────────────
  {id:173,category:"Ethics",sanskrit:"अहिंसा प्रतिष्ठायां तत्सन्निधौ वैरत्यागः।",translation:"When non-violence is established, all enmity is abandoned in its presence.",meaning:"A person of genuine non-violence creates a field of safety around them. Others feel it without being told.",source:"Yoga Sutras 2.35"},
  {id:174,category:"Truth",sanskrit:"सत्यप्रतिष्ठायां क्रियाफलाश्रयत्वम्।",translation:"When one is established in truthfulness, actions and their results are grounded in it.",meaning:"A life built on honesty has a kind of natural coherence. Lies require maintenance; truth sustains itself.",source:"Yoga Sutras 2.36"},
  {id:175,category:"Giving",sanskrit:"अपरिग्रहस्थैर्ये जन्मकथन्तासम्बोधः।",translation:"When non-possessiveness is established, knowledge of past and future lives arises.",meaning:"When you stop clutching what you have, a profound clarity about what truly matters naturally emerges.",source:"Yoga Sutras 2.39"},

  // ── BHAKTI SUTRAS / MISC WISDOM ───────────────────────────────────────────
  {id:176,category:"Relationships",sanskrit:"सत्सङ्गत्वे निस्सङ्गत्वम्।",translation:"From the company of the wise comes non-attachment.",meaning:"The right relationships don't increase your neediness — they free you from it. Choose companions who expand you.",source:"Vivekachudamani 2"},
  {id:177,category:"Learning",sanskrit:"सद्गुरोः अनुग्रहात्।",translation:"Through the grace of the true teacher.",meaning:"No matter how intelligent you are, a teacher who has walked the path you seek can save you years of wrong turns.",source:"Vivekachudamani"},
  {id:178,category:"Gratitude",sanskrit:"गुरुर्ब्रह्मा गुरुर्विष्णुः गुरुर्देवो महेश्वरः।",translation:"The teacher is Brahma, the teacher is Vishnu, the teacher is Maheshvara.",meaning:"Those who guide us — parents, mentors, teachers — are divine forces in human form. Honour them.",source:"Guru Stotram"},
  {id:179,category:"Learning",sanskrit:"विनयेन ज्ञानम्।",translation:"Knowledge comes through humility.",meaning:"The cup that is already full cannot be filled. Empty yourself of certainty and you become teachable.",source:"Subhashitani"},
  {id:180,category:"Joy",sanskrit:"यस्तु सर्वाणि भूतानि आत्मन्येवानुपश्यति।",translation:"One who sees all beings in the self, and the self in all beings — feels no hatred.",meaning:"When you recognise yourself in others, the experience of separation, judgment, and loneliness dissolves.",source:"Isha Upanishad 6"},

  // ── ADDITIONAL BHAGAVAD GITA ───────────────────────────────────────────────
  {id:181,category:"Surrender",sanskrit:"चेतसा सर्वकर्माणि मयि संन्यस्य मत्परः।",translation:"Dedicating all actions to Me with your mind, be devoted to Me.",meaning:"When you act in service of what is highest rather than for ego-satisfaction, you naturally make better decisions.",source:"Bhagavad Gita 12.6"},
  {id:182,category:"Practice",sanskrit:"अनित्यमसुखं लोकमिमं प्राप्य भजस्व माम्।",translation:"Having come to this impermanent, joyless world, engage in devotion to Me.",meaning:"Life is short and largely uncomfortable. The wisest response is to orient toward what is permanent and meaningful.",source:"Bhagavad Gita 9.33"},
  {id:183,category:"Knowledge",sanskrit:"सर्वस्य चाहं हृदि सन्निविष्टो।",translation:"I am seated in the hearts of all.",meaning:"The source of your deepest intuitions is not the ego but something deeper and wiser. Learn to listen to it.",source:"Bhagavad Gita 15.15"},
  {id:184,category:"Equanimity",sanskrit:"समदुःखसुखं धीरम् सोऽमृतत्वाय कल्पते।",translation:"One who is the same in pain and pleasure, steady — that person is worthy of immortality.",meaning:"Emotional steadiness — not through suppression but through perspective — is the mark of the truly mature.",source:"Bhagavad Gita 2.15"},
  {id:185,category:"Nature",sanskrit:"भूमिरापोऽनलो वायुः खं मनो बुद्धिरेव च।",translation:"Earth, water, fire, air, ether, mind, intelligence, ego — these are My eight-fold nature.",meaning:"You are made of the same substance as stars, rivers, and forests. Honour the natural world as your extended body.",source:"Bhagavad Gita 7.4"},
  {id:186,category:"Wisdom",sanskrit:"ज्ञानिनामग्रणीर्मत्स्याद्बहूनां जन्मनामन्ते।",translation:"At the end of many lives, the wise person attains Me.",meaning:"Wisdom is not achieved in one moment but cultivated over a lifetime of genuine seeking and honest living.",source:"Bhagavad Gita 7.19"},
  {id:187,category:"Purpose",sanskrit:"इमं विवस्वते योगं प्रोक्तवानहमव्ययम्।",translation:"I taught this imperishable yoga to the sun god.",meaning:"The wisdom you seek is ancient and has sustained humanity across countless generations. Trust it.",source:"Bhagavad Gita 4.1"},
  {id:188,category:"Courage",sanskrit:"श्रेयान्युद्धं स्वधर्म्यं शान्तिर्भ्रष्टा।",translation:"Better to engage rightly in conflict than to withdraw from one's duty for the sake of peace.",meaning:"Conflict avoided out of cowardice creates deeper suffering. Sometimes the courageous path is through, not around.",source:"Bhagavad Gita 2.31"},
  {id:189,category:"Giving",sanskrit:"यज्ञदानतपःकर्म न त्याज्यं कार्यमेव तत्।",translation:"Acts of sacrifice, charity, and austerity should never be abandoned — they purify even the wise.",meaning:"Even for those who have achieved much, acts of giving and service continue to purify and deepen the soul.",source:"Bhagavad Gita 18.5"},
  {id:190,category:"Freedom",sanskrit:"मुक्तसङ्गोऽनहंवादी धृत्युत्साहसमन्वितः।",translation:"Free from attachment, without ego, with fortitude and enthusiasm.",meaning:"The qualities of the liberated person: not indifferent, but unattached; not passive, but enthusiastic.",source:"Bhagavad Gita 18.26"},

  // ── FINAL SET ──────────────────────────────────────────────────────────────
  {id:191,category:"Present",sanskrit:"अतीतं नानुशोचन्ति नापि भविष्यद्भयाः।",translation:"They do not grieve over the past nor fear the future.",meaning:"The enlightened person lives fully in the present — not denying the past or future but not imprisoned by them.",source:"Mahabharata Shanti Parva"},
  {id:192,category:"Breath",sanskrit:"प्राणायामः परं तपः।",translation:"Pranayama — breath control — is the highest austerity.",meaning:"Before any complex practice, before any technique, breath regulation is the most powerful tool available to you.",source:"Manusmriti 2.83"},
  {id:193,category:"Gratitude",sanskrit:"अन्नदाता सुखी भव।",translation:"May the one who gives food live happily.",meaning:"The act of nourishing others — physically, emotionally, spiritually — returns joy to the giver.",source:"Traditional blessing"},
  {id:194,category:"Unity",sanskrit:"सर्वे भवन्तु सुखिनः सर्वे सन्तु निरामयाः।",translation:"May all beings be happy; may all beings be free from disease.",meaning:"Begin every day by expanding your concern beyond yourself. This simple prayer transforms the quality of your day.",source:"Brihadaranyaka Upanishad"},
  {id:195,category:"Purpose",sanskrit:"यावज्जीवमधीते।",translation:"Study for as long as you live.",meaning:"The Vedic tradition never allows the student to graduate. A love of learning is the mark of a complete life.",source:"Taittiriya Upanishad"},
  {id:196,category:"Harmony",sanskrit:"लोकाः समस्ताः सुखिनो भवन्तु।",translation:"May all the worlds be happy.",meaning:"Not just your people, your country, your tribe — all worlds, all beings. Expand your circle of care.",source:"Traditional Vedic prayer"},
  {id:197,category:"Meditation",sanskrit:"मौनं स्वाध्यायो वेदाभ्यासश्च।",translation:"Silence, self-study, and practice of the Vedas.",meaning:"Three practices for a single day: quiet time, honest self-reflection, and engagement with wisdom literature.",source:"Taittiriya Upanishad"},
  {id:198,category:"Wisdom",sanskrit:"न जायते म्रियते वा कदाचिन्नायं भूत्वा भविता वा न भूयः।",translation:"The soul is never born nor dies at any time. It has not come into being and will not come into being.",meaning:"Your deepest self is beyond birth and death. This recognition removes the root of all fear.",source:"Bhagavad Gita 2.20"},
  {id:199,category:"Freedom",sanskrit:"ज्ञानाग्निः सर्वकर्माणि भस्मसात् कुरुते।",translation:"The fire of knowledge burns all actions to ashes.",meaning:"True self-knowledge dissolves the weight of past actions, guilt, and karma. Understanding liberates.",source:"Bhagavad Gita 4.37"},
  {id:200,category:"Purpose",sanskrit:"यो माम् पश्यति सर्वत्र सर्वं च मयि पश्यति।",translation:"One who sees Me everywhere, and sees everything in Me — I am not lost to them, nor are they lost to Me.",meaning:"When you recognise the sacred in everything — in every person, every moment, every challenge — life becomes worship.",source:"Bhagavad Gita 6.30"},
  {id:201,category:"Courage",sanskrit:"नैनं छिन्दन्ति शस्त्राणि नैनं दहति पावकः।",translation:"Weapons cannot cut the soul, fire cannot burn it.",meaning:"At your core is something indestructible. No criticism, failure, or loss can reach what you truly are.",source:"Bhagavad Gita 2.23"},
  {id:202,category:"Self",sanskrit:"अन्तरात्मा साक्षी।",translation:"The inner self is the witness.",meaning:"There is a part of you that simply watches — without judgment, without reactivity. That is your truest self.",source:"Vedic tradition"},
  {id:203,category:"Peace",sanskrit:"परमं शान्तिं निर्वाणं मत्प्रसादाद् गमिष्यसि।",translation:"By My grace, you will attain supreme peace and the eternal abode.",meaning:"Grace — the support of something larger than yourself — is available when you genuinely open to it.",source:"Bhagavad Gita 18.62"},
  {id:204,category:"Harmony",sanskrit:"सहनाववतु सहनौभुनक्तु।",translation:"May we be protected together; may we be nourished together.",meaning:"The Vedic vision of community is mutual protection and nourishment — not competition but co-flourishing.",source:"Taittiriya Upanishad 2.2.2"},
  {id:205,category:"Learning",sanskrit:"सा विद्या या विमुक्तये।",translation:"That which liberates is true education.",meaning:"Any knowledge that does not ultimately free you from ignorance, fear, and suffering is not worth its name.",source:"Vishnu Purana 1.19.41"},
];

const VEDIC_WISDOM = [
  {id:"bg",era:"~500 BCE",title:"Bhagavad Gita",subtitle:"The Song of the Lord",desc:"A 700-verse dialogue between prince Arjuna and Krishna on the battlefield of Kurukshetra — covering duty, action, devotion, knowledge, and the nature of the self.",concepts:["Karma Yoga","Dharma","Atman","Detachment","Moksha"],principles:[{h:"Act without attachment",t:"Perform your duties fully, but release your grip on outcomes. This dissolves anxiety and brings clarity."},{h:"Know your true self",t:"Beyond the body and mind lies the Atman — pure, unchanging consciousness. You are not your problems."},{h:"Follow your Dharma",t:"Your unique path of right action is your contribution to the world. Abandoning it creates suffering."}],highlight:"\"You have a right to perform your actions, but you are not entitled to the fruits of your actions.\"",source:"Bhagavad Gita 2.47"},
  {id:"upan",era:"~800–200 BCE",title:"The Upanishads",subtitle:"108 Philosophical Dialogues",desc:"A collection of philosophical texts forming the theoretical basis of Hinduism. They explore consciousness, reality, the nature of Brahman, and the relationship between the individual self (Atman) and the universal consciousness.",concepts:["Brahman","Atman","Consciousness","Non-duality","Meditation"],principles:[{h:"Tat Tvam Asi — Thou art That",t:"Your deepest self is identical with the ground of all being. Separation is illusion."},{h:"Neti Neti — Not this, not this",t:"Reality transcends all descriptions. Wisdom comes through negating what you are not."},{h:"Meditation as inquiry",t:"Sit quietly and ask: who is the one who is aware? This question leads to liberation."}],highlight:"\"The knower of Brahman becomes Brahman.\"",source:"Mundaka Upanishad 3.2.9"},
  {id:"rg",era:"~1500–1200 BCE",title:"The Rigveda",subtitle:"The Oldest Vedic Scripture",desc:"The oldest of the four Vedas, containing 1,028 hymns to the natural forces and cosmic order (Rita). It is the foundational text of Vedic civilization and contains deep ecological and cosmological wisdom.",concepts:["Rita (Cosmic Order)","Agni (Fire)","Indra","Soma","Yajna"],principles:[{h:"Harmony with nature",t:"The Vedic worldview sees nature as sacred — not a resource to exploit but a living system to honour."},{h:"Collective prayer and ritual",t:"Yajna (sacrifice/ritual) is the mechanism by which humans participate in the cosmic order."},{h:"One truth, many paths",t:"\"Ekam sat vipra bahudha vadanti\" — Truth is one, the wise call it by many names."}],highlight:"\"Let noble thoughts come to us from all directions.\"",source:"Rigveda 1.89.1"},
  {id:"yoga",era:"~400 CE",title:"Yoga Sutras of Patanjali",subtitle:"The Science of the Mind",desc:"196 aphorisms systematizing the practice of yoga as a means of understanding and stilling the mind. Patanjali defines yoga as 'chitta vritti nirodha' — the cessation of the fluctuations of the mind.",concepts:["Ashtanga Yoga","Pratyahara","Dhyana","Samadhi","Yamas & Niyamas"],principles:[{h:"Still the mind",t:"Yoga is not a posture — it is the art of quieting the constant noise of thought."},{h:"The eight limbs",t:"Ethics → Discipline → Posture → Breath → Withdrawal → Concentration → Meditation → Absorption."},{h:"Practice and non-attachment",t:"Abhyasa (steady practice) and Vairagya (non-attachment) are the twin pillars of all progress."}],highlight:"\"Yoga is the cessation of the fluctuations of the mind.\"",source:"Yoga Sutras 1.2"},
  {id:"art",era:"~300 BCE",title:"Arthashastra",subtitle:"Ancient Science of Statecraft",desc:"Kautilya's treatise on statecraft, economic policy, and military strategy — often compared to Machiavelli. It covers leadership, governance, diplomacy, and the ethics of power.",concepts:["Artha (Wealth/Purpose)","Leadership","Strategy","Governance","Ethics of Power"],principles:[{h:"The leader must master themselves first",t:"Self-discipline and ethical conduct are prerequisites for effective leadership of others."},{h:"Balance the four aims",t:"Dharma, Artha, Kama, and Moksha must all be harmonised — neglecting any one causes imbalance."},{h:"Preparation over reaction",t:"The wise leader anticipates change rather than merely responding to it."}],highlight:"\"The king who is energetic, who has conquered the six enemies of man, who remembers favours done to him — he shall triumph.\"",source:"Arthashastra 1.6"},
  {id:"pur",era:"~500 BCE – 500 CE",title:"The Puranas",subtitle:"Stories of Creation & Cosmos",desc:"18 major texts containing mythology, cosmology, genealogies of gods and kings, and practical wisdom. They encode deep philosophical truths in the form of accessible narratives and stories.",concepts:["Creation","Vishnu","Shiva","Shakti","Karma & Rebirth"],principles:[{h:"Stories as teaching vehicles",t:"Complex truths about consciousness, ethics, and cosmology are made accessible through mythology."},{h:"Everything is cyclical",t:"The Puranic cosmology of Yugas teaches that all civilisations rise, peak, decline, and renew."},{h:"The divine is in everything",t:"Every person, plant, and creature is a manifestation of the same underlying consciousness."}],highlight:"\"Without a purpose, no one should enter a house. Without a purpose, no one moves.\"",source:"Bhagavata Purana"},
];

